    def daysBetweenDates(self, date1: str, date2: str) -> int:
        import datetime
        y1,m1,d1 = map(int, date1.split('-'))
        y2,m2,d2 = map(int, date2.split('-'))
        a = datetime.date(y1,m1,d1)
        b = datetime.date(y2,m2,d2)
        return abs((a-b).days)

