class Solution:
    def daysBetweenDates(self, date1: str, date2: str) -> int:
        def is_leap(y):
            return (y % 4 == 0 and y % 100 != 0) or (y % 400 == 0)
        def to_days(s):
            y, m, d = map(int, s.split('-'))
            days = 0
            for yr in range(1971, y):
                days += 366 if is_leap(yr) else 365
            month_days = [31, 29 if is_leap(y) else 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]
            for mo in range(m - 1):
                days += month_days[mo]
            days += d
            return days
        return abs(to_days(date1) - to_days(date2))

